(window.webpackJsonp=window.webpackJsonp||[]).push([[370],{997:function(r,n){r.exports="\x3c!-- \r\ntitle: 内网穿透\r\nsort: \r\n--\x3e \r\n\r\n> 推荐使用[Sakura](https://www.natfrp.com/)\r\n>\r\n> 咱学校ip好像被sakura给ban了\r\n>\r\n> 自己用阿里云搭吧\r\n\r\n## 自搭\r\n\r\n> [Release](https://github.com/fatedier/frp/releases)\r\n>\r\n> 使用开源项目frp-v0.32\r\n\r\n```bash\r\nwget https://github.com/fatedier/frp/releases/download/v0.32.0/frp_0.32.0_linux_amd64.tar.gz\r\ntar -zxvf frp_0.32.0_linux_amd64.tar.gz\r\n```\r\n\r\n### 编辑配置\r\n\r\n> frpc是客户端(client),frps是服务端(server)\r\n>\r\n> 别忘记开端口!\r\n\r\n```ini\r\n# vim frpc.ini\r\n[common]\r\n# 连接端口\r\nbind_port = 7000\r\n# 控制板端口,用于网页查看状态\r\ndashboard_port = 7800\r\n# 连接密码\r\ntoken = passswd_token\r\n# 控制板登录用户名密码\r\ndashboard_user = name\r\ndashboard_pwd = passwd\r\n\r\n# 运行一下试试\r\n./frpc -c ./frpc.init\r\n```\r\n\r\n### 自启动\r\n\r\n> 为frps创建services\r\n>\r\n> 项目中service文件已经写好,直接copy过去就可以\r\n\r\n```bash\r\n# 进入frp的systemd目录\r\n# cp frps.service /lib/systemd/system/\r\n# @的服务可自定义配置文件名\r\n# cp frps@.service /lib/systemd/system/\r\n# 下面是service中的内容\r\n[Unit]\r\nDescription=Frp Server Service\r\nAfter=network.target\r\n\r\n[Service]\r\nType=simple\r\nUser=nobody\r\nRestart=on-failure\r\nRestartSec=5s\r\n# 注意下面这行\r\nExecStart=/usr/bin/frps -c /etc/frp/frps.ini\r\n\r\n[Install]\r\nWantedBy=multi-user.target\r\n\r\n# 把frps与配置文件拷贝到其应在的目录\r\ncp frps /usr/bin\r\nmkdir /etc/frp       \r\ncp frps.ini /etc/frp\r\n\r\n# 启动服务\r\n# 重载services\r\nsystemctl daemon-reload \r\n# 尝试运行\r\nsystemctl start frps\r\n# 开机自启动\r\nsystemctl enable frps\r\n```\r\n\r\n## 客户端配置\r\n\r\n```ini\r\n# vim frpc.ini\r\n[common]\r\n# 写服务端信息\r\nserver_addr = ip\r\nserver_port = 7000\r\ntoken = passwd_token\r\n \r\n[localhost]\r\n# 写你要开放的端口\r\ntype = tcp\r\nlocal_ip = 127.0.0.1\r\nlocal_port = 22\r\n# 用英文写的下面这行注释,这句话十分重要\r\nremote_port = [make sure your server open this port on filrewall]\r\n```\r\n\r\n### 自启\r\n\r\n```bash\r\n# 进入frp的systemd目录\r\n# cp frpc.service /lib/systemd/system/\r\n# cp frpc@.service /lib/systemd/system/\r\n# 下面是其中的内容\r\n[Unit]\r\nDescription=Frp Client Service\r\nAfter=network.target\r\n\r\n[Service]\r\nType=simple\r\nUser=nobody\r\nRestart=on-failure\r\nRestartSec=5s\r\n# 注意这行\r\nExecStart=/usr/bin/frpc -c /etc/frp/frpc.ini\r\nExecReload=/usr/bin/frpc reload -c /etc/frp/frpc.ini\r\n\r\n[Install]\r\nWantedBy=multi-user.target\r\n\r\n# 把frpc与配置文件拷贝到其应在的目录\r\ncp frpc /usr/bin\r\nmkdir /etc/frp\r\ncp frpc.ini /etc/frp\r\n# 尝试运行\r\n/usr/bin/frpc -c /etc/frp/frpc.ini\r\n\r\n# 启动服务\r\n# 重载services\r\nsystemctl daemon-reload \r\n# 尝试运行\r\nsystemctl start frpc\r\n# 开机自启动\r\nsystemctl enable frpc\r\n```\r\n\r\n"}}]);